import * as React from "react"
import { ark } from "@ark-ui/react/factory"

import { cn } from "@/registry/ark-nova/lib/utils"

function Skeleton({
  className,
  ...props
}: React.ComponentProps<typeof ark.div>) {
  return (
    <ark.div
      data-slot="skeleton"
      className={cn("animate-pulse rounded-md bg-accent", className)}
      {...props}
    />
  )
}

export { Skeleton }
